import React, { createContext, useContext, useEffect, useMemo, useReducer, useState } from 'react';
import { ActivityIndicator, Alert, Button, SafeAreaView, StyleSheet, Text, TextInput, View } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AUTH_TOKEN_KEY = '@auth_token';
const AUTH_USER_KEY = '@auth_user';

const AuthContext = createContext(null);

const initialState = {
  loading: true,
  token: null,
  user: null,
};

function authReducer(state, action) {
  switch (action.type) {
    case 'RESTORE':
      return {
        loading: false,
        token: action.token ?? null,
        user: action.user ?? null,
      };
    case 'SIGN_IN':
      return {
        loading: false,
        token: action.token,
        user: action.user,
      };
    case 'SIGN_OUT':
      return {
        loading: false,
        token: null,
        user: null,
      };
    default:
      return state;
  }
}

export function AuthProvider({ children }) {
  const [state, dispatch] = useReducer(authReducer, initialState);

  useEffect(() => {
    let mounted = true;

    const restoreAuth = async () => {
      try {
        const [token, userJson] = await Promise.all([
          AsyncStorage.getItem(AUTH_TOKEN_KEY),
          AsyncStorage.getItem(AUTH_USER_KEY),
        ]);

        const user = userJson ? JSON.parse(userJson) : null;

        if (mounted) {
          dispatch({ type: 'RESTORE', token, user });
        }
      } catch (error) {
        if (mounted) {
          dispatch({ type: 'RESTORE', token: null, user: null });
        }
      }
    };

    restoreAuth();

    return () => {
      mounted = false;
    };
  }, []);

  const auth = useMemo(
    () => ({
      loading: state.loading,
      token: state.token,
      user: state.user,
      signIn: async (credentials) => {
        const { email, password } = credentials || {};

        if (!email || !password) {
          throw new Error('Email and password are required.');
        }

        const response = await fakeLoginApi({ email, password });

        await Promise.all([
          AsyncStorage.setItem(AUTH_TOKEN_KEY, response.token),
          AsyncStorage.setItem(AUTH_USER_KEY, JSON.stringify(response.user)),
        ]);

        dispatch({ type: 'SIGN_IN', token: response.token, user: response.user });
      },
      signOut: async () => {
        await Promise.all([
          AsyncStorage.removeItem(AUTH_TOKEN_KEY),
          AsyncStorage.removeItem(AUTH_USER_KEY),
        ]);

        dispatch({ type: 'SIGN_OUT' });
      },
    }),
    [state.loading, state.token, state.user]
  );

  return <AuthContext.Provider value={auth}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return ctx;
}

async function fakeLoginApi({ email, password }) {
  await new Promise((resolve) => setTimeout(resolve, 900));

  if (email.trim().toLowerCase() === 'demo@app.com' && password === 'password123') {
    return {
      token: 'demo-jwt-token-abc123',
      user: {
        id: 'user_1',
        name: 'Demo User',
        email: 'demo@app.com',
      },
    };
  }

  throw new Error('Invalid email or password.');
}

function AuthLoadingScreen() {
  return (
    <SafeAreaView style={styles.centered}>
      <ActivityIndicator size="large" />
      <Text style={styles.loadingText}>Restoring session...</Text>
    </SafeAreaView>
  );
}

function LoginScreen() {
  const { signIn } = useAuth();
  const [email, setEmail] = useState('demo@app.com');
  const [password, setPassword] = useState('password123');
  const [submitting, setSubmitting] = useState(false);

  const onSubmit = async () => {
    try {
      setSubmitting(true);
      await signIn({ email, password });
    } catch (error) {
      Alert.alert('Login Failed', error.message || 'Unable to sign in.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <Text style={styles.title}>Sign In</Text>
      <TextInput
        value={email}
        onChangeText={setEmail}
        autoCapitalize="none"
        autoComplete="email"
        keyboardType="email-address"
        placeholder="Email"
        style={styles.input}
      />
      <TextInput
        value={password}
        onChangeText={setPassword}
        secureTextEntry
        placeholder="Password"
        style={styles.input}
      />
      <Button title={submitting ? 'Signing In...' : 'Sign In'} onPress={onSubmit} disabled={submitting} />
      <Text style={styles.helper}>Use demo@app.com / password123</Text>
    </SafeAreaView>
  );
}

function HomeScreen() {
  const { user, token, signOut } = useAuth();

  return (
    <SafeAreaView style={styles.container}>
      <Text style={styles.title}>Welcome</Text>
      <Text style={styles.text}>Name: {user?.name || 'Unknown'}</Text>
      <Text style={styles.text}>Email: {user?.email || 'Unknown'}</Text>
      <Text style={styles.text} numberOfLines={1}>Token: {token || 'No token'}</Text>
      <View style={styles.spacer} />
      <Button title="Sign Out" onPress={signOut} />
    </SafeAreaView>
  );
}

export default function App() {
  return (
    <AuthProvider>
      <AppNavigator />
    </AuthProvider>
  );
}

function AppNavigator() {
  const { loading, token } = useAuth();

  if (loading) return <AuthLoadingScreen />;

  return token ? <HomeScreen /> : <LoginScreen />;
}

